'use client';

import type { LessonRecurrence } from '@soenglish/shared-types';
import { Button, Field } from '../../../components/ui';
import type { LessonFormState, LessonModalMode } from '../types';
import type { MockStudent } from '../../../mocks';
import styles from '../../../app/calendar/page.module.scss';

export function LessonModal({
  mode,
  canEdit,
  form,
  onChange,
  onClose,
  onSubmit,
  students,
}: {
  mode: LessonModalMode;
  canEdit: boolean;
  form: LessonFormState;
  onChange: (next: LessonFormState) => void;
  onClose: () => void;
  onSubmit: () => void;
  students: MockStudent[];
}) {
  const weekDayOptions = [
    { value: 1, label: 'Mon' },
    { value: 2, label: 'Tue' },
    { value: 3, label: 'Wed' },
    { value: 4, label: 'Thu' },
    { value: 5, label: 'Fri' },
    { value: 6, label: 'Sat' },
    { value: 7, label: 'Sun' },
  ];

  return (
    <div className={styles.modalOverlay} onClick={onClose}>
      <div className={styles.modal} onClick={(e) => e.stopPropagation()}>
        <div className={styles.modalTitle}>{mode === 'create' ? 'Plan lesson' : 'Edit lesson'}</div>
        <div className={styles.modalFields}>
          <div className={styles.fieldGroup}>
            <label className={styles.fieldLabel}>Title</label>
            <Field
              className={styles.fieldInput}
              value={form.title}
              disabled={!canEdit}
              onChange={(e) => onChange({ ...form, title: e.target.value })}
            />
          </div>
          <div className={styles.fieldGroup}>
            <label className={styles.fieldLabel}>Type</label>
            <Field
              as="select"
              className={styles.fieldInput}
              value={form.type}
              disabled={!canEdit}
              onChange={(e) => onChange({ ...form, type: e.target.value as LessonFormState['type'] })}
            >
              <option value="grammar">Grammar</option>
              <option value="vocabulary">Vocabulary</option>
              <option value="speaking">Speaking</option>
              <option value="listening">Listening</option>
            </Field>
          </div>
          <div className={styles.fieldGroup}>
            <label className={styles.fieldLabel}>Date</label>
            <Field
              type="date"
              className={styles.fieldInput}
              value={form.date}
              disabled={!canEdit}
              onChange={(e) => onChange({ ...form, date: e.target.value })}
            />
          </div>
          <div className={styles.fieldGroup}>
            <label className={styles.fieldLabel}>Start time</label>
            <Field
              type="time"
              className={styles.fieldInput}
              value={form.startTime}
              disabled={!canEdit}
              onChange={(e) => onChange({ ...form, startTime: e.target.value })}
            />
          </div>
          <div className={styles.fieldGroup}>
            <label className={styles.fieldLabel}>Duration (min)</label>
            <Field
              type="number"
              className={styles.fieldInput}
              min={15}
              step={5}
              value={String(form.duration)}
              disabled={!canEdit}
              onChange={(e) => onChange({ ...form, duration: Number(e.target.value) })}
            />
          </div>
          <div className={styles.fieldGroup}>
            <label className={styles.fieldLabel}>Recurrence</label>
            <Field
              as="select"
              className={styles.fieldInput}
              value={form.recurrence}
              disabled={!canEdit}
              onChange={(e) => onChange({ ...form, recurrence: e.target.value as LessonRecurrence })}
            >
              <option value="none">No repeat</option>
              <option value="daily">Daily</option>
              <option value="weekly">Weekly</option>
              <option value="monthly">Monthly</option>
            </Field>
          </div>
          {form.recurrence === 'weekly' ? (
            <div className={styles.fieldGroup}>
              <label className={styles.fieldLabel}>Week days</label>
              <div className={styles.weekDaysRow}>
                {weekDayOptions.map((day) => {
                  const selected = form.weeklyDays.includes(day.value);
                  return (
                    <button
                      key={day.value}
                      type="button"
                      className={`${styles.weekDayChip} ${selected ? styles.weekDayChipActive : ''}`}
                      onClick={() => {
                        const next = selected
                          ? form.weeklyDays.filter((weekday) => weekday !== day.value)
                          : [...form.weeklyDays, day.value];
                        onChange({ ...form, weeklyDays: next.sort((a, b) => a - b) });
                      }}
                    >
                      {day.label}
                    </button>
                  );
                })}
              </div>
            </div>
          ) : null}
          <div className={styles.fieldGroup}>
            <label className={styles.fieldLabel}>Student</label>
            <Field
              as="select"
              className={styles.fieldInput}
              value={form.studentId}
              disabled={!canEdit}
              onChange={(e) => {
                const nextStudent = students.find((student) => student.id === e.target.value);
                if (!nextStudent) return;
                onChange({
                  ...form,
                  studentId: nextStudent.id,
                  studentName: nextStudent.fullName,
                });
              }}
            >
              {students.map((student) => (
                <option key={student.id} value={student.id}>
                  {student.fullName}
                </option>
              ))}
            </Field>
          </div>
          {mode === 'edit' && (
            <div className={styles.fieldGroup}>
              <label className={styles.fieldLabel}>Update scope</label>
              <Field
                as="select"
                className={styles.fieldInput}
                value={form.applyToSeries ? 'series' : 'single'}
                disabled={!canEdit}
                onChange={(e) => onChange({ ...form, applyToSeries: e.target.value === 'series' })}
              >
                <option value="single">Only this lesson</option>
                <option value="series">Whole series</option>
              </Field>
            </div>
          )}
          <div className={styles.fieldGroup}>
            <label className={styles.fieldLabel}>Notes</label>
            <Field
              as="textarea"
              className={styles.fieldInput}
              rows={3}
              value={form.notes}
              disabled={!canEdit}
              onChange={(e) => onChange({ ...form, notes: e.target.value })}
            />
          </div>
        </div>
        <div className={styles.modalActions}>
          <Button type="button" className={styles.modalCancelBtn} onClick={onClose}>
            Cancel
          </Button>
          <Button type="button" className={styles.modalConfirmBtn} onClick={onSubmit} disabled={!canEdit}>
            {canEdit ? (mode === 'create' ? 'Save lesson' : 'Update lesson') : 'Send change request'}
          </Button>
        </div>
      </div>
    </div>
  );
}

